args.sparql:
SELECT ?plaintiffLabel WHERE {
  ?case rdfs:label "Brown v. Board of Education"@en.
  ?case wdt:P10982 ?plaintiff.
  ?plaintiff rdfs:label ?plaintiffLabel.
  FILTER (lang(?plaintiffLabel) = "en").
}

SELECT ?plaintiffLabel WHERE {
  wd:Q218529 wdt:P10982 ?plaintiff.
  ?plaintiff rdfs:label ?plaintiffLabel.
  FILTER (lang(?plaintiffLabel) = "en").
}

SELECT ?plaintiff WHERE {
  wd:Q218529 wdt:P10982 ?plaintiff.
  ?plaintiff rdfs:label ?label.
  FILTER (LANG(?label) = 'en')
}
